import { useState } from "react";
import UserNavbar from "../../components/UserNavbar/UserNavbar";
import "./Return_user.css"; // Separate CSS file

export default function BorrowedBooks() {
  const [borrowedBooks, setBorrowedBooks] = useState([
    { id: 1, title: "The Great Gatsby", author: "F. Scott Fitzgerald", returned: false },
    { id: 2, title: "1984", author: "George Orwell", returned: false },
  ]);

  const handleReturn = (id) => {
    setBorrowedBooks((prevBooks) =>
      prevBooks.map((book) =>
        book.id === id ? { ...book, returned: true } : book
      )
    );
  };

  return (
    <div className="borrowed-books-container">
      <UserNavbar />
      <h1 className="page-title">Borrowed Books</h1>

      <h2 className="library-subtitle">Currently Borrowed</h2>
      {borrowedBooks.some((book) => !book.returned) ? (
        <ul className="book-list">
          {borrowedBooks.map((book) =>
            !book.returned ? (
              <li key={book.id} className="book-item">
                <strong>
                  {book.title} <span>by {book.author}</span>
                </strong>
                <button 
                  className="return-button"
                  onClick={() => handleReturn(book.id)}
                >
                  Return
                </button>
              </li>
            ) : null
          )}
        </ul>
      ) : (
        <p className="empty-message">No borrowed books</p>
      )}

      <h2 className="library-subtitle">Returned Books</h2>
      {borrowedBooks.some((book) => book.returned) ? (
        <ul className="book-list">
          {borrowedBooks
            .filter((book) => book.returned)
            .map((book) => (
              <li key={book.id} className="book-item returned">
                <strong>
                  {book.title} <span>by {book.author}</span>
                </strong>
                <span className="returned-tag">Returned</span>
              </li>
            ))}
        </ul>
      ) : (
        <p className="empty-message">No books returned yet</p>
      )}
    </div>
  );
}
